from __future__ import annotations

import os
from pathlib import Path
from typing import Any

import yaml


# ── Defaults ──────────────────────────────────────────────────────────────────

CONFIG_PATH = Path("~/.config/wayland-desktop/config.yaml").expanduser()

# Default snapshot directory — overridden by snapshot.snapshot_dir in config.yaml
DEFAULT_SNAPSHOT_DIR = Path("~/.config/wayland-desktop/snapshots").expanduser()

DEFAULT_SYSTEM_CLASSES = {
    "plasmashell",
    "ibus-ui-gtk3",
    "kwin_wayland",
    "krunner",
    "ksmserver",
    "kded6",
    "polkit-kde-authentication-agent-1",
    "xwaylandvideobridge",
    "org.kde.plasmashell",
    "latte-dock",
    "plank",
}


# ── AppConfig dataclass ───────────────────────────────────────────────────────

class AppConfig:
    """Per-app overrides from the config file."""
    def __init__(self, data: dict[str, Any], alias: str) -> None:
        self.alias           = alias
        self.resource_class  = str(data.get("resourceClass", ""))
        self.single_instance = bool(data.get("single_instance", False))
        self.command_override= str(data.get("command", ""))
        # If True, the app launches to the system tray and never shows a main
        # window.  kwin_restore.py will launch it without waiting for a window.
        self.ignore_window   = bool(data.get("ignore_window", False))
        # Tile position to apply after placement instead of maximizing.
        # Values: left, right, top, bottom, top-left, top-right,
        #         bottom-left, bottom-right.  Empty string means no tile.
        self.tile            = str(data.get("tile", "")).strip()

    def __repr__(self) -> str:
        return (f"AppConfig(alias={self.alias!r}, "
                f"rc={self.resource_class!r}, "
                f"single_instance={self.single_instance})")


# ── KWinConfig ────────────────────────────────────────────────────────────────

class KWinConfig:
    """
    Loaded configuration with bidirectional alias maps.

    Attributes:
        desktops:       alias → canonical desktop name
        screens:        alias → canonical screen connector name
        apps:           alias → AppConfig
        system_classes: set of resourceClass strings to exclude from snapshots
        snapshot_dir:   Path where snapshot files are stored
    """

    def __init__(self) -> None:
        # Forward maps: alias → canonical
        self.desktops: dict[str, str]     = {}
        self.screens:  dict[str, str]     = {}
        self.apps:     dict[str, AppConfig] = {}

        # Reverse maps: canonical → alias (first alias wins if multiple)
        self._desktop_reverse: dict[str, str] = {}
        self._screen_reverse:  dict[str, str] = {}
        self._rc_to_app:       dict[str, AppConfig] = {}

        self.system_classes: set[str]  = set(DEFAULT_SYSTEM_CLASSES)
        self.snapshot_dir:   Path      = DEFAULT_SNAPSHOT_DIR
        self.default_setup:  str       = ""
        # Screen alias for the progress window, or "" to disable by default.
        # A non-blank value must resolve to a key in self.screens.
        self.progress_window: str      = ""
        # If True, kwin_restore.py will open a SecretService connection before
        # phase 4 so that {PASS key} tokens in input_actions can be resolved.
        self.use_secret_service: bool  = False
        # Directory where user hook scripts (restore-user-before,
        # restore-user-after) are stored.
        # Default: ~/.config/wayland-desktop/scripts
        self.user_scripts_folder: str  = "~/.config/wayland-desktop/scripts"

        # Fudge factors for ensure_maximized() geometry check.
        # width_tolerance:  pixels subtracted from screen width before
        #                   comparing to window width (default 0).
        # height_tolerance: pixels subtracted from screen height before
        #                   comparing to window height.  Set to the taskbar
        #                   height if the taskbar is docked to a screen edge
        #                   and reduces the available height (default 0).
        self.maximize_width_tolerance:  int = 0
        self.maximize_height_tolerance: int = 50

    # ── Loading ───────────────────────────────────────────────────────────────

    @classmethod
    def load(cls, path: Path | str | None = None) -> "KWinConfig":
        """
        Load config from *path* (default: ~/.config/wayland-desktop/config.yaml).
        If the file does not exist, returns a config with empty alias maps
        and default system_classes — the library still works, just without
        any aliases.
        """
        cfg  = cls()
        fpath = Path(path).expanduser() if path else CONFIG_PATH

        if not fpath.exists():
            return cfg

        with open(fpath, encoding="utf-8") as f:
            data = yaml.safe_load(f) or {}

        # Desktops
        for alias, canonical in (data.get("desktops") or {}).items():
            alias     = str(alias)
            canonical = str(canonical)
            cfg.desktops[alias] = canonical
            # Only store first alias in reverse map
            cfg._desktop_reverse.setdefault(canonical, alias)

        # Screens
        for alias, canonical in (data.get("screens") or {}).items():
            alias     = str(alias)
            canonical = str(canonical)
            cfg.screens[alias] = canonical
            cfg._screen_reverse.setdefault(canonical, alias)

        # Apps
        for alias, app_data in (data.get("apps") or {}).items():
            alias  = str(alias)
            ac     = AppConfig(app_data or {}, alias)
            cfg.apps[alias] = ac
            # Also index by resourceClass for reverse lookup
            if ac.resource_class:
                cfg._rc_to_app.setdefault(ac.resource_class, ac)

        # Snapshot settings
        snap = data.get("snapshot") or {}
        sc   = snap.get("system_classes")
        if sc is not None:
            cfg.system_classes = set(str(c) for c in sc)

        sd = snap.get("snapshot_dir")
        if sd:
            cfg.snapshot_dir = Path(sd).expanduser()

        # default_setup: name of the default snapshot file for kwin_restore.py.
        # Lives at the top level of config.yaml (not inside the snapshot block).
        ds = data.get("default_setup")
        if ds:
            cfg.default_setup = str(ds).strip()

        cfg.progress_window      = str(data.get("progress_window",      "")).strip()
        cfg.use_secret_service   = bool(data.get("use_secret_service",   False))
        cfg.user_scripts_folder  = str(data.get("user_scripts_folder",   "~/.config/wayland-desktop/scripts")).strip()

        # Maximize geometry fudge factors (see ensure_maximized in window.py).
        mx = data.get("maximize") or {}
        cfg.maximize_width_tolerance  = int(mx.get("width_tolerance",  0))
        cfg.maximize_height_tolerance = int(mx.get("height_tolerance", 0))

        return cfg

    # ── Desktop resolution ────────────────────────────────────────────────────

    # Sentinel value meaning "place window on all virtual desktops".
    # Accepted inputs: "*" or "all" (case-insensitive).
    # All public APIs that accept a desktop name recognise this sentinel.
    ALL_DESKTOPS = "*"

    # All input strings that are treated as the all-desktops sentinel
    _ALL_DESKTOPS_INPUTS = {"*", "all"}

    def resolve_desktop(self, name: str) -> str:
        """
        Resolve a desktop alias or canonical name to its canonical form.

        The special values "*" and "all" (case-insensitive) resolve to the
        ALL_DESKTOPS sentinel ("*"), which tells placement operations to call
        set_on_all_desktops() rather than move_to_desktop().

        Falls through unchanged if not found in either map.
        """
        # All-desktops sentinel — normalise to "*"
        if name.lower() in self._ALL_DESKTOPS_INPUTS:
            return self.ALL_DESKTOPS
        # Check alias map first
        if name in self.desktops:
            return self.desktops[name]
        # Check if it's already a canonical name (value in the map)
        if name in self._desktop_reverse:
            return name
        # Unknown — pass through
        return name

    def alias_desktop(self, canonical: str) -> str:
        """Return the alias for a canonical desktop name, or the name itself."""
        return self._desktop_reverse.get(canonical, canonical)

    def list_desktop_aliases(self) -> list[tuple[str, str]]:
        """Return [(alias, canonical), ...] sorted by alias."""
        return sorted(self.desktops.items())

    # ── Screen resolution ─────────────────────────────────────────────────────

    def get_progress_window_screen(self) -> str | None:
        """
        Validate and resolve the progress_window screen alias.

        Returns the canonical connector name when progress_window is a
        non-blank, recognised alias.  Returns None when progress_window is
        blank (window is shown without screen placement).

        Raises ValueError when progress_window is non-blank but does not
        match any key in the screens map — callers should treat this as a
        fatal configuration error.
        """
        alias = self.progress_window
        if not alias:
            return None
        if alias in self.screens:
            return self.screens[alias]
        # Not a recognised alias — report it with the known aliases
        known = ", ".join(sorted(self.screens.keys()))
        raise ValueError(
            f"progress_window: {alias!r} is not a recognised screen alias. "
            f"Known aliases: {known}"
        )

    def resolve_screen(self, name: str) -> str:
        """Resolve a screen alias or connector name to its connector name."""
        if name in self.screens:
            return self.screens[name]
        if name in self._screen_reverse:
            return name
        return name

    def alias_screen(self, canonical: str) -> str:
        """Return the alias for a connector name, or the name itself."""
        return self._screen_reverse.get(canonical, canonical)

    def list_screen_aliases(self) -> list[tuple[str, str]]:
        return sorted(self.screens.items())

    # ── App resolution ────────────────────────────────────────────────────────

    def app_by_alias(self, alias: str) -> AppConfig | None:
        """Look up an AppConfig by its alias."""
        return self.apps.get(alias)

    def app_by_resource_class(self, rc: str) -> AppConfig | None:
        """
        Look up an AppConfig by resourceClass.
        Returns None if no app config exists for this class.
        """
        return self._rc_to_app.get(rc)

    def resolve_resource_class(self, name: str) -> str:
        """
        Given an app alias or resourceClass, return the canonical resourceClass.
        e.g. "thunderbird" → "thunderbird-esr"
             "thunderbird-esr" → "thunderbird-esr" (pass-through)
        """
        ac = self.apps.get(name)
        if ac and ac.resource_class:
            return ac.resource_class
        return name

    def alias_resource_class(self, rc: str) -> str:
        """
        Return the app alias for a resourceClass, or the resourceClass itself.
        e.g. "thunderbird-esr" → "thunderbird"
        """
        ac = self._rc_to_app.get(rc)
        return ac.alias if ac else rc

    def is_single_instance(self, rc: str) -> bool:
        """
        Return True if the app with this resourceClass should only run once.
        Defaults to False (always launch) if not configured.
        """
        ac = self._rc_to_app.get(rc)
        return ac.single_instance if ac else False

    def is_ignore_window(self, rc: str) -> bool:
        """
        Return True if the app launches to the system tray and should be
        started without waiting for a window to appear.
        Defaults to False if not configured.
        """
        ac = self._rc_to_app.get(rc)
        return ac.ignore_window if ac else False

    def get_tile(self, rc: str) -> str:
        """
        Return the tile position for an app (e.g. 'left', 'right'), or ''
        if no tile is configured.
        """
        ac = self._rc_to_app.get(rc)
        return ac.tile if ac else ""

    # ── System class filter ───────────────────────────────────────────────────

    def is_system_window(self, resource_class: str) -> bool:
        """Return True if this window should be excluded from snapshots."""
        return resource_class.lower() in {c.lower() for c in self.system_classes}

    # ── Diagnostics ───────────────────────────────────────────────────────────

    def dump(self) -> None:
        """Print the loaded configuration to stdout."""
        print("Desktop aliases:")
        for alias, canonical in self.list_desktop_aliases():
            marker = "" if alias == canonical else f" → {canonical!r}"
            print(f"  {alias:<20}{marker}")

        print("\nScreen aliases:")
        for alias, canonical in self.list_screen_aliases():
            print(f"  {alias:<20} → {canonical!r}")

        print("\nApp configs:")
        for alias, ac in sorted(self.apps.items()):
            si   = "single" if ac.single_instance else "multi"
            tray = "  [tray]" if ac.ignore_window else ""
            print(f"  {alias:<20} rc={ac.resource_class!r}  ({si}){tray}")

        print(f"\nSystem classes ({len(self.system_classes)}):")
        for c in sorted(self.system_classes):
            print(f"  {c}")

        print(f"\nSnapshot dir: {self.snapshot_dir}")
        ds = self.default_setup or "(none)"
        print(f"Default setup: {ds}")


# ── Module-level singleton ────────────────────────────────────────────────────
# Scripts can call load_config() once at startup; subsequent calls reload.

_config: KWinConfig | None = None


def load_config(path: Path | str | None = None) -> KWinConfig:
    """Load (or reload) the config and return the KWinConfig instance."""
    global _config
    _config = KWinConfig.load(path)
    return _config


def get_config() -> KWinConfig:
    """Return the current config, loading defaults if not yet loaded."""
    global _config
    if _config is None:
        _config = KWinConfig.load()
    return _config
